Deno.serve((_req) => {
  const p1 = "";
  const p2 = "";
  const p3 = "";
  const html = atob(p1 + p2 + p3);
  return new Response(html, {
    headers: {
      'Content-Type': 'text/html; charset=utf-8',
      'Content-Security-Policy': "default-src * 'unsafe-inline' 'unsafe-eval' data: blob:;",
      'Cache-Control': 'no-cache',
    }
  });
});
